const AppContext = createContext();
function App() {
const [theme, setTheme] = useState("dark");
const [user, setUser] = useState(null);
return (
<AppContext.Provider value={{ theme, setTheme, user, setUser }}>
<Everything />
</AppContext.Provider>
);
}
